// Alle Items holen
const items = $input.all();

// Item mit API-Daten finden
const apiItem = items.find(i =>
  i.json.token &&
  i.json.server &&
  i.json.task
);

if (!apiItem) {
  throw new Error("API-Item (token/server/task) wurde nicht gefunden.");
}

// Item mit Dokumente-Array finden
const docsItem = items.find(i =>
  Array.isArray(i.json.Dokumente)
);

if (!docsItem) {
  throw new Error("'Dokumente'-Array wurde nicht gefunden.");
}

// Item mit echten Binary-Daten finden
const binaryItem = items.find(i =>
  i.binary && Object.keys(i.binary).length > 0
);

if (!binaryItem) {
  throw new Error("Binary-Item wurde nicht gefunden.");
}

// Dokumentenliste extrahieren
const docs = docsItem.json.Dokumente;

// Binary Keys wie: ["Dokumente_0", "Dokumente_1"]
const binaryKeys = Object.keys(binaryItem.binary);

// Output für Split Items
const output = [];

// MATCH PER INDEX – EINZIG RICHTIGE LÖSUNG
docs.forEach((doc, index) => {

  const binaryKey = binaryKeys[index];
  const binaryData = binaryItem.binary[binaryKey];

  if (!binaryData) {
    throw new Error(
      `Binary-Daten für Index ${index} (${binaryKey}) nicht gefunden.`
    );
  }

  output.push({
    json: {
      fileName: doc.filename,
      mimeType: doc.mimetype,
      size: doc.size,

      // API-Daten
      token: apiItem.json.token,
      server: apiItem.json.server,
      task: apiItem.json.task,
    },
    binary: {
      data: binaryData
    }
  });
});

return output;

// Input ist ein Array von Items
const items = $input.all();
const json = items.map(i => i.json);

// 1) Hole task, server, original filenames
// (die stehen in den ersten beiden Objekten)
const token = json.find(o => o.token)?.token;
const task = json.find(o => o.task)?.task;
const server = json.find(o => o.server)?.server;

// 2) Hole alle Original-Dateinamen (aus fileName)
const originalFilenames = json
  .filter(o => o.fileName)
  .map(o => o.fileName);

// 3) Hole alle server_filenames (aus server_filename)
const serverFilenames = json
  .filter(o => o.server_filename)
  .map(o => o.server_filename);

// 4) Baue das required "files"-Array im iLovePDF Format
const files = serverFilenames.map((serverFilename, i) => ({
  server_filename: serverFilename,
  filename: originalFilenames[i] || `file_${i+1}.pdf`
}));

// 5) Rückgabe im korrekten Format
return [
  {
    json: {
      token,
      task,
      server,
      files
    }
  }
];

// =====================================================
// 1. Alle Input-Items holen
// =====================================================
const items = $input.all();

// =====================================================
// 2. API-Item finden (token / server / task)
// =====================================================
const apiItem = items.find(i =>
  i.json?.token &&
  i.json?.server &&
  i.json?.task
);

if (!apiItem) {
  throw new Error("API-Item (token/server/task) wurde nicht gefunden.");
}

// =====================================================
// 3. Dokument-Item finden (fileName/mimeType ODER filename/mimetype)
// =====================================================
const docItem = items.find(i =>
  (
    (i.json?.fileName && i.json?.mimeType) ||
    (i.json?.filename && i.json?.mimetype)
  )
);

if (!docItem) {
  throw new Error(
    "Dokument-Item wurde nicht gefunden (fileName/mimeType oder filename/mimetype)."
  );
}

// =====================================================
// 4. Dokument-Felder normalisieren
// =====================================================
const fileName =
  docItem.json.fileName ??
  docItem.json.filename ??
  null;

const mimeType =
  docItem.json.mimeType ??
  docItem.json.mimetype ??
  null;

const size =
  docItem.json.size ??
  null;

// =====================================================
// 5. Binary robust ermitteln
//    - binary.data
//    - binary.file
//    - erstes vorhandenes Binary-Feld
// =====================================================
let binaryData = null;

if (docItem.binary) {
  if (docItem.binary.data) {
    binaryData = docItem.binary.data;
  } else if (docItem.binary.file) {
    binaryData = docItem.binary.file;
  } else {
    const binaryValues = Object.values(docItem.binary);
    if (binaryValues.length > 0) {
      binaryData = binaryValues[0];
    }
  }
}

if (!binaryData) {
  throw new Error("Binary-Daten wurden nicht gefunden.");
}

// =====================================================
// 6. EIN sauberes Output-Item zurückgeben
// =====================================================
return [
  {
    json: {
      fileName,
      mimeType,
      size,
      token: apiItem.json.token,
      server: apiItem.json.server,
      task: apiItem.json.task,
    },
    binary: {
      data: binaryData
    }
  }
];
